/****** Object:  UserDefinedFunction [dbo].[GetColumnValue]    Script Date: 2021/02/01 09:55:23 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GetColumnValue](
    @String VARCHAR(MAX),
    @Delimiter CHAR(1),
    @Column INT = 1
)
    RETURNS VARCHAR(MAX)
AS
BEGIN
    DECLARE @idx INT
    DECLARE @slice VARChar(MAX)
SELECT @idx = 1
           IF LEN(@String)<1 OR @String IS NULL
        RETURN NULL
DECLARE @ColCnt INT
    SET @ColCnt = 1
    WHILE (@idx != 0)
BEGIN
            SET @idx = CHARINDEX(@Delimiter,@String)
            IF @idx!=0
BEGIN
                    IF (@ColCnt = @Column)
                        RETURN LEFT(@String,@idx - 1)
                    SET @ColCnt = @ColCnt + 1
END
            SET @String = RIGHT(@String,LEN(@String) - @idx)
            IF LEN(@String) = 0 BREAK
END
RETURN @String
END
GO
/****** Object:  UserDefinedFunction [dbo].[Split]    Script Date: 2021/02/01 09:55:23 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create FUNCTION [dbo].[Split](@String varchar(MAX), @Delimiter char(1))
returns @temptable TABLE (items varchar(MAX))
as
begin
    declare @idx int
    declare @slice varchar(8000)

select @idx = 1
           if len(@String)<1 or @String is null  return

    while @idx!= 0
begin
        set @idx = charindex(@Delimiter,@String)
        if @idx!=0
            set @slice = left(@String,@idx - 1)
        else
            set @slice = @String

        if(len(@slice)>0)
            insert into @temptable(Items) values(@slice)

        set @String = right(@String,len(@String) - @idx)
        if len(@String) = 0 break
end
return
end;
GO
