/****** Object:  View [dbo].[SecurityHierarchyView]    Script Date: 2021/02/01 09:55:23 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


--drop view [dbo].[SecurityHierarchyView];
CREATE view [dbo].[SecurityHierarchyView]
AS
    with tbl AS
    (
    select st.SecurityTokenID           'id'
    , st.SecurityTokenFriendlyName 'name'
    , sxs.ParentSecurityTokenID    'ParentID'
    from Security.SecurityTokenXSecurityToken sxs (nolock)
    right outer join Security.SecurityToken st (nolock)
    on sxs.ChildSecurityTokenID = st.SecurityTokenID
    left join Security.SecurityToken stChild (nolock)
    on sxs.ChildSecurityTokenID = stChild.SecurityTokenID
),
    SecurityPath
AS (
    -- anchor
    SELECT CONVERT(VARCHAR(36),id) id,
    CONVERT(VARCHAR(36),[Name]) [Name],
    CONVERT(VARCHAR(36),ParentID) ParentID,
    CONVERT(VARCHAR(1500),[Name]) AS "Pather",
    CONVERT(VARCHAR(1500),id)  AS "Path"
    FROM tbl
    WHERE ParentId IS NULL
    UNION ALL
    --recursive member
    SELECT  CONVERT(VARCHAR(36),t.id) id,
    CONVERT(VARCHAR(36),t.[Name]) [Name],
    CONVERT(VARCHAR(36),t.ParentID) ParentID,
    CAST(CONVERT(VARCHAR(36),a.name) + '/' + (CONVERT(VARCHAR(36),t.Name)) AS VARCHAR(1500)) AS "Path",
    CAST((a."Path" + '/' + convert(VARCHAR(36),t.id)) AS VARCHAR(1500)) AS "PathCrypt"
    FROM tbl AS t
    JOIN SecurityPath AS a
    ON t.ParentId = a.id
)
SELECT s.id, s.Name, s.ParentID, s.Pather, s.Path, '1' as 'One'
FROM SecurityPath s
GO
