CREATE view [dbo].[ClassificationHierarchyView]
AS
    with tbl AS
    (
    select st.ClassificationID        'id'
    , st.ClassificationName      'name'
    , sxs.ParentClassificationID 'ParentID'
    from Classification.ClassificationXClassification sxs (nolock)
    right outer join Classification.Classification st (nolock)
    on sxs.ChildClassificationID = st.ClassificationID
    left join Classification.Classification stChild (nolock)
    on sxs.ChildClassificationID = stChild.ClassificationID
),
    SecurityPath
AS (
    -- anchor
    SELECT CONVERT(VARCHAR(36),id) id,
    CONVERT(VARCHAR(36),[Name]) [Name],
    CONVERT(VARCHAR(36),ParentID) ParentID,
    CONVERT(VARCHAR(1500),[Name]) AS "Pather",
    CONVERT(VARCHAR(1500),id)  AS "Path"
    FROM tbl
    WHERE ParentId IS NULL
    UNION ALL
    --recursive member
    SELECT  CONVERT(VARCHAR(36),t.id) id,
