/****** Object:  View [dbo].[LU_Classifications]    Script Date: 2021/02/01 09:55:23 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[LU_Classifications]
AS
select distinct cdc.ClassificationDataConceptID,cdc.ClassificationDataConceptName,
                c.ClassificationID 'Level1ID',c.ClassificationName 'Level1Name',
                cDesc.ClassificationID  'Level2ID',cDesc.ClassificationName'Level2Name',
                cDesc2.ClassificationID 'Level3ID',cDesc2.ClassificationName'Level3Name',
                cDesc3.ClassificationID 'Level4ID',cDesc3.ClassificationName'Level4Name',
                cDesc4.ClassificationID 'Level5ID',cDesc4.ClassificationName'Level5Name'
from Classification.Classification c
         left join Classification.ClassificationXClassification cxc
                   on c.ClassificationID = cxc.ParentClassificationID
         left join ClassificationHierarchyView chv
                   on c.ClassificationID = chv.ParentID
    outer apply dbo.Split(chv.Path,'/') chvS
	left join Classification.Classification cDesc
on cxc.ChildClassificationID = cDesc.ClassificationID
    left join Classification.ClassificationDataConcept cdc
    on c.ClassificationDataConceptID = cdc.ClassificationDataConceptID


    left join Classification.ClassificationXClassification cxc2
    on cDesc.ClassificationID = cxc2.ParentClassificationID
    left join Classification.Classification cDesc2
    on cxc2.ChildClassificationID = cDesc2.ClassificationID

    left join Classification.ClassificationXClassification cxc3
    on cDesc2.ClassificationID = cxc3.ParentClassificationID
    left join Classification.Classification cDesc3
    on cxc3.ChildClassificationID = cDesc3.ClassificationID


    left join Classification.ClassificationXClassification cxc4
    on cDesc3.ClassificationID = cxc4.ParentClassificationID
    left join Classification.Classification cDesc4
    on cxc4.ChildClassificationID = cDesc4.ClassificationID

where chvS.items = c.ClassificationID
GO
