CREATE PROCEDURE [dbo].[LoadInitialTimeData]
AS
BEGIN
SET IDENTITY_INSERT [Time].[DayParts] ON
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (2, N'Early Morning', N'Between 3.30am and 6.30 am', 2)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (3, N'Morning', N'Between 6.30am and 9am', 3)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (4, N'Late Morning', N'Between 9am and 10.30am', 4)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (5, N'Early Afternoon', N'Between 10.30 and 12pm', 5)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (6, N'Afternoon', N'Between 12pm and 2pm', 6)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (7, N'Late Afternoon', N'Between 2pm and 3.30pm', 7)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (8, N'Early Evening', N'Between 3.30pm and 4.30pm', 8)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (9, N'Evening', N'Between 4.30pm and 7pm', 9)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (10, N'Late Evening', N'Between 7pm and 9.30pm', 10)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (11, N'Midnight Evening', N'Between 9.30pm and 12am', 11)
INSERT [Time].[DayParts] ([DayPartID], [DayPartName], [DayPartDescription], [DayPartSortOrder]) VALUES (12, N'Midnight Morning', N'Between 12am and 3.30am', 1)
SET IDENTITY_INSERT [Time].[DayParts] OFF

    SET IDENTITY_INSERT [Time].[DayNames] ON
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (1, N'Sunday', N'Sun', 0, N'S', N'Su', 0, N'Weekend')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (2, N'Monday', N'Mon', 1, N'M', N'Mo', 1, N'Weekday')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (3, N'Tuesday', N'Tue', 2, N'T', N'Tu', 1, N'Weekday')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (4, N'Wednesday', N'Wed', 3, N'W', N'We', 1, N'Weekday')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (5, N'Thursday', N'Thur', 4, N'T', N'Th', 1, N'Weekday')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (6, N'Friday', N'Fri', 5, N'F', N'Fr', 1, N'Weekday')
    INSERT [Time].[DayNames] ([DayNameID], [DayName], [DayShortName], [DaySortOrder], [DayAbbreviation], [DayLongAbbreviation], [DayIsBusinessDay], [DayBusinessDayClassification]) VALUES (7, N'Saturday', N'Sat', 6, N'S', N'Sa', 0, N'Weekend')
    SET IDENTITY_INSERT [Time].[DayNames] OFF
    SET IDENTITY_INSERT [Time].[MonthOfYear] ON
