/****** Object:  StoredProcedure [dbo].[MoveToExistingInvolvedParty]    Script Date: 2021/02/01 09:55:26 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE   PROCEDURE [dbo].[MoveToExistingInvolvedParty]
	-- Add the parameters for the stored procedure here
	@originalIP uniqueidentifier,
	@newIP uniqueidentifier
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	UPDATE Arrangement.ArrangementXInvolvedParty
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Event.EventXInvolvedParty
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Event.EventXInvolvedParty
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXAddress
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXClassification
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXInvolvedParty
		set ParentInvolvedPartyID = @newIP
	where ParentInvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXInvolvedParty
		set ChildInvolvedPartyID = @newIP
	where ChildInvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXInvolvedPartyIdentificationType
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXInvolvedPartyNameType
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXInvolvedPartyType
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXProduct
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXProductType
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXResourceItem
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Party.InvolvedPartyXRules
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
	UPDATE Rules.RulesXInvolvedParty
		set InvolvedPartyID = @newIP
	where InvolvedPartyID = @originalIP;
END
GO
/****** Object:  StoredProcedure [dbo].[UpdateHierarchyAll]    Script Date: 2021/02/01 09:55:26 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[UpdateHierarchyAll]
AS
BEGIN
UPDATE Security.SecurityHierarchy
SET Path     = v.Path,
    ParentID = v.ParentID,
    Pather   = v.Pather
    FROM Security.SecurityHierarchy (nolock) sh
             inner join Security.SecurityHierarchyView (nolock) v
on sh.id = v.id
where sh.Path <> v.Path
END
GO
/****** Object:  StoredProcedure [dbo].[UpdateSecurityHierarchyAll]    Script Date: 2021/02/01 09:55:26 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[UpdateSecurityHierarchyAll]
AS
BEGIN

    --DECLARE @id bigint;
--SET @id = -9223372036854723203;
--Insert Into SecurityHierarchyParents (id,value)
select sh.id,
       cs.value --SplitData
into #tempshp
from Security.SecurityHierarchy sh (nolock)
    cross apply STRING_SPLIT(sh.Path, '/') cs


delete
from Security.SecurityHierarchyParents
where value not in (select value from #tempshp);

insert into Security.SecurityHierarchyParents (id, value)
select t.id, t.value
from #tempshp t
         left join Security.SecurityHierarchyParents shp
                   on t.id = shp.id
                       and t.value = shp.value
where shp.value is null

drop table #tempshp;

END
GO
